#nullable disable

using System.Collections.Generic;
using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;

namespace Microsoft.CodeAnalysis.CSharp
{
    /// <summary>
    /// Defines a strategy for resolving symbols within a binder scope.
    /// Implementations provide context-specific lookup behavior (e.g., type resolution,
    /// member access, namespace resolution).
    /// </summary>
    internal interface ISymbolResolutionStrategy
    {
        /// <summary>
        /// Performs a lookup within a single binder scope using this strategy.
        /// </summary>
        void LookupSymbols(
            LookupResult result,
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo);

        /// <summary>
        /// Returns true if the search should continue to the next scope in the chain.
        /// </summary>
        bool ShouldContinueSearch(LookupResult result);
    }

    /// <summary>
    /// Captures the result of a unified symbol resolution, including resolved symbols
    /// and any associated diagnostics.
    /// </summary>
    internal sealed class SymbolResolutionResult
    {
        /// <summary>
        /// The symbols found during resolution.
        /// </summary>
        public ImmutableArray<Symbol> Symbols { get; }

        /// <summary>
        /// The diagnostic, if any, produced during resolution.
        /// </summary>
        public DiagnosticInfo Diagnostic { get; }

        /// <summary>
        /// Whether the resolution found at least one viable symbol.
        /// </summary>
        public bool IsViable { get; }

        /// <summary>
        /// Whether the resolution found no symbols.
        /// </summary>
        public bool IsEmpty => Symbols.IsDefaultOrEmpty;

        public SymbolResolutionResult(ImmutableArray<Symbol> symbols, DiagnosticInfo diagnostic, bool isViable)
        {
            Symbols = symbols;
            Diagnostic = diagnostic;
            IsViable = isViable;
        }

        internal static readonly SymbolResolutionResult Empty =
            new SymbolResolutionResult(ImmutableArray<Symbol>.Empty, diagnostic: null, isViable: false);
    }

    /// <summary>
    /// Strategy for looking up type symbols, considering both named types and type parameters.
    /// </summary>
    internal sealed class TypeResolutionStrategy : ISymbolResolutionStrategy
    {
        public static readonly TypeResolutionStrategy Instance = new TypeResolutionStrategy();

        private TypeResolutionStrategy() { }

        public void LookupSymbols(
            LookupResult result,
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            var typeOptions = options | LookupOptions.NamespacesOrTypesOnly;
            binder.LookupSymbolsInSingleBinder(result, name, arity, basesBeingResolved: null, typeOptions, binder, diagnose, ref useSiteInfo);
        }

        public bool ShouldContinueSearch(LookupResult result)
            => !result.IsMultiViable;
    }

    /// <summary>
    /// Strategy for looking up member symbols within a qualified type or namespace.
    /// </summary>
    internal sealed class MemberAccessResolutionStrategy : ISymbolResolutionStrategy
    {
        private readonly NamespaceOrTypeSymbol _qualifier;

        public MemberAccessResolutionStrategy(NamespaceOrTypeSymbol qualifier)
        {
            _qualifier = qualifier;
        }

        public void LookupSymbols(
            LookupResult result,
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            var memberOptions = options & ~LookupOptions.NamespacesOrTypesOnly;
            binder.LookupMembersInternal(result, _qualifier, name, arity, basesBeingResolved: null, memberOptions, binder, diagnose, ref useSiteInfo);
        }

        public bool ShouldContinueSearch(LookupResult result)
            => !result.IsMultiViable;
    }

    /// <summary>
    /// Strategy for looking up namespace symbols only.
    /// </summary>
    internal sealed class NamespaceResolutionStrategy : ISymbolResolutionStrategy
    {
        public static readonly NamespaceResolutionStrategy Instance = new NamespaceResolutionStrategy();

        private NamespaceResolutionStrategy() { }

        public void LookupSymbols(
            LookupResult result,
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            var nsOptions = options | LookupOptions.NamespacesOrTypesOnly | LookupOptions.MustNotBeInstance;
            binder.LookupSymbolsInSingleBinder(result, name, arity, basesBeingResolved: null, nsOptions, binder, diagnose, ref useSiteInfo);
        }

        public bool ShouldContinueSearch(LookupResult result)
            => !result.IsMultiViable;
    }

    /// <summary>
    /// Provides a unified entry point for symbol resolution that consolidates common lookup
    /// patterns across different binding contexts. Resolution walks the binder scope chain
    /// using the provided <see cref="ISymbolResolutionStrategy"/> to control lookup behavior
    /// at each scope and to decide when to stop searching.
    /// </summary>
    internal sealed class UnifiedSymbolResolver
    {
        /// <summary>
        /// Resolves symbols by walking the binder scope chain starting at <paramref name="binder"/>,
        /// using the given <paramref name="strategy"/> to perform the lookup at each scope.
        /// </summary>
        /// <param name="binder">The starting binder (innermost scope).</param>
        /// <param name="name">The symbol name to look up.</param>
        /// <param name="arity">The arity (number of type parameters). Pass 0 for non-generic.</param>
        /// <param name="strategy">The resolution strategy that controls lookup per scope.</param>
        /// <param name="options">Additional lookup options.</param>
        /// <returns>A <see cref="SymbolResolutionResult"/> capturing the found symbols and diagnostics.</returns>
        public SymbolResolutionResult Resolve(
            Binder binder,
            string name,
            int arity,
            ISymbolResolutionStrategy strategy,
            LookupOptions options = LookupOptions.Default)
        {
            if (binder is null) return SymbolResolutionResult.Empty;
            if (name is null) return SymbolResolutionResult.Empty;

            var useSiteInfo = CompoundUseSiteInfo<AssemblySymbol>.DiscardedDependencies;

            // First pass: lookup without diagnostics
            var result = LookupResult.GetInstance();
            try
            {
                WalkScopeChain(result, binder, name, arity, strategy, options, diagnose: false, ref useSiteInfo);

                if (!result.IsMultiViable && !result.IsClear)
                {
                    // Second pass: retry with diagnostics to get richer error info
                    result.Clear();
                    useSiteInfo = CompoundUseSiteInfo<AssemblySymbol>.DiscardedDependencies;
                    WalkScopeChain(result, binder, name, arity, strategy, options, diagnose: true, ref useSiteInfo);
                }

                return BuildResult(result);
            }
            finally
            {
                result.Free();
            }
        }

        private static void WalkScopeChain(
            LookupResult result,
            Binder startingBinder,
            string name,
            int arity,
            ISymbolResolutionStrategy strategy,
            LookupOptions options,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            for (var scope = startingBinder; scope != null && strategy.ShouldContinueSearch(result); scope = scope.Next)
            {
                strategy.LookupSymbols(result, scope, name, arity, options, diagnose, ref useSiteInfo);
            }
        }

        private static SymbolResolutionResult BuildResult(LookupResult result)
        {
            var symbols = result.Symbols.ToImmutableArray();
            var diagnostic = result.Error;
            var isViable = result.IsMultiViable;
            return new SymbolResolutionResult(symbols, diagnostic, isViable);
        }
    }
}

