using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Xunit;

namespace Microsoft.CodeAnalysis.CSharp.UnitTests
{
    /// <summary>
    /// Tests for the UnifiedSymbolResolver and associated types.
    /// </summary>
    public class UnifiedSymbolResolverTests
    {
        // ──────────────────────────────────────────────────────────────────────
        // ISymbolResolutionStrategy existence / shape tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void ISymbolResolutionStrategy_IsInterface()
        {
            var type = typeof(ISymbolResolutionStrategy);
            Assert.True(type.IsInterface);
        }

        [Fact]
        public void ISymbolResolutionStrategy_HasLookupSymbolsMethod()
        {
            var type = typeof(ISymbolResolutionStrategy);
            // LookupSymbols is a method on the interface
            var method = type.GetMethod("LookupSymbols");
            Assert.NotNull(method);
        }

        [Fact]
        public void ISymbolResolutionStrategy_HasShouldContinueSearchMethod()
        {
            var type = typeof(ISymbolResolutionStrategy);
            var method = type.GetMethod("ShouldContinueSearch");
            Assert.NotNull(method);
            Assert.Equal(typeof(bool), method.ReturnType);
        }

        // ──────────────────────────────────────────────────────────────────────
        // TypeResolutionStrategy tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void TypeResolutionStrategy_ImplementsInterface()
        {
            Assert.IsAssignableFrom<ISymbolResolutionStrategy>(TypeResolutionStrategy.Instance);
        }

        [Fact]
        public void TypeResolutionStrategy_IsSingleton()
        {
            var a = TypeResolutionStrategy.Instance;
            var b = TypeResolutionStrategy.Instance;
            Assert.Same(a, b);
        }

        [Fact]
        public void TypeResolutionStrategy_ShouldContinueSearch_ReturnsTrueWhenEmpty()
        {
            var strategy = TypeResolutionStrategy.Instance;
            var result = LookupResult.GetInstance();
            try
            {
                // An empty result means we haven't found anything yet — should keep searching.
                Assert.True(result.IsClear);
                Assert.True(strategy.ShouldContinueSearch(result));
            }
            finally
            {
                result.Free();
            }
        }

        // ──────────────────────────────────────────────────────────────────────
        // MemberAccessResolutionStrategy tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void MemberAccessResolutionStrategy_ImplementsInterface()
        {
            // Constructing with null is intentional for a pure type-system check
            var strategy = new MemberAccessResolutionStrategy(qualifier: null);
            Assert.IsAssignableFrom<ISymbolResolutionStrategy>(strategy);
        }

        [Fact]
        public void MemberAccessResolutionStrategy_ShouldContinueSearch_ReturnsTrueWhenEmpty()
        {
            var strategy = new MemberAccessResolutionStrategy(qualifier: null);
            var result = LookupResult.GetInstance();
            try
            {
                Assert.True(strategy.ShouldContinueSearch(result));
            }
            finally
            {
                result.Free();
            }
        }

        // ──────────────────────────────────────────────────────────────────────
        // NamespaceResolutionStrategy tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void NamespaceResolutionStrategy_ImplementsInterface()
        {
            Assert.IsAssignableFrom<ISymbolResolutionStrategy>(NamespaceResolutionStrategy.Instance);
        }

        [Fact]
        public void NamespaceResolutionStrategy_IsSingleton()
        {
            Assert.Same(NamespaceResolutionStrategy.Instance, NamespaceResolutionStrategy.Instance);
        }

        [Fact]
        public void NamespaceResolutionStrategy_ShouldContinueSearch_ReturnsTrueWhenEmpty()
        {
            var strategy = NamespaceResolutionStrategy.Instance;
            var result = LookupResult.GetInstance();
            try
            {
                Assert.True(strategy.ShouldContinueSearch(result));
            }
            finally
            {
                result.Free();
            }
        }

        // ──────────────────────────────────────────────────────────────────────
        // SymbolResolutionResult tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void SymbolResolutionResult_Empty_IsEmpty()
        {
            var empty = SymbolResolutionResult.Empty;
            Assert.True(empty.IsEmpty);
            Assert.False(empty.IsViable);
            Assert.Null(empty.Diagnostic);
        }

        [Fact]
        public void SymbolResolutionResult_Constructor_StoresValues()
        {
            var symbols = ImmutableArray<Symbol>.Empty;
            var result = new SymbolResolutionResult(symbols, diagnostic: null, isViable: false);
            Assert.Equal(symbols, result.Symbols);
            Assert.Null(result.Diagnostic);
            Assert.False(result.IsViable);
        }

        [Fact]
        public void SymbolResolutionResult_IsEmpty_WhenDefaultOrEmpty()
        {
            var withDefault = new SymbolResolutionResult(default, null, false);
            Assert.True(withDefault.IsEmpty);

            var withEmpty = new SymbolResolutionResult(ImmutableArray<Symbol>.Empty, null, false);
            Assert.True(withEmpty.IsEmpty);
        }

        // ──────────────────────────────────────────────────────────────────────
        // UnifiedSymbolResolver existence tests
        // ──────────────────────────────────────────────────────────────────────

        [Fact]
        public void UnifiedSymbolResolver_CanBeInstantiated()
        {
            var resolver = new UnifiedSymbolResolver();
            Assert.NotNull(resolver);
        }

        [Fact]
        public void UnifiedSymbolResolver_HasResolveMethod()
        {
            var type = typeof(UnifiedSymbolResolver);
            var method = type.GetMethod("Resolve");
            Assert.NotNull(method);
            Assert.Equal(typeof(SymbolResolutionResult), method.ReturnType);
        }

        [Fact]
        public void UnifiedSymbolResolver_ResolveReturnsEmpty_WhenBinderIsNull()
        {
            var resolver = new UnifiedSymbolResolver();
            var result = resolver.Resolve(binder: null, name: "Foo", arity: 0, TypeResolutionStrategy.Instance);
            Assert.NotNull(result);
            Assert.True(result.IsEmpty);
        }

        [Fact]
        public void UnifiedSymbolResolver_ResolveReturnsEmpty_WhenNameIsNull()
        {
            var resolver = new UnifiedSymbolResolver();
            var result = resolver.Resolve(binder: null, name: null, arity: 0, TypeResolutionStrategy.Instance);
            Assert.NotNull(result);
            Assert.True(result.IsEmpty);
        }
    }
}

